tocol-tag {\n            background: #F5F7FA;\n            border: 1px solid #e2e8f0;\n            padding: 12px 24px;\n            border-radius: 8px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: #475569;\n            font-weight: 500;\n        }\n/* Divi overrides */\n.et_pb_section .protocol-inner h3{font-weight:700 !important;line-height:1.3 !important;font-size:24px !important}\n.et_pb_section .protocol-tag{font-weight:500 !important;padding-bottom:0 !important}\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D: HTML has corner-tl at 0.10 opacity (barely visible). corner-tl not in super-d presets — omitted for fidelity. */\n/* === INTEGRATION (S8) === */\n/* TODO: Review and remap class selectors to use int prefix */\n/* TODO: Add section container: .integration-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.integration-section {\n            padding: 80px 0;\n            background: #F5F7FA;\n        }\n.integration-header {\n            text-align: center;\n            max-width: 700px;\n            margin: 0 auto 60px;\n            padding: 0 24px;\n        }\n.integration-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            color: #000864;\n            margin-bottom: 16px;\n        }\n.integration-header p {\n            font-size: 18px;\n            color: #5b6b80;\n        }\n.integration-diagram {\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            gap: 24px;\n            flex-wrap: wrap;\n            max-width: 900px;\n            margin: 0 auto 48px;\n            padding: 0 24px;\n            min-height: auto;\n        }\n.integration-node {\n            position: static;\n            width: auto;\n            height: auto;\n            background: #fff;\n            border: 2px solid #e2e8f0;\n            border-radius: 16px;\n            padding: 24px 32px;\n            text-align: center;\n            transition: all 0.3s ease;\n        }\n.integration-node.aiot-active {\n            background: linear-gradient(135deg, #00AFF0, #003CC8);\n            border-color: #00AFF0;\n        }\n.integration-node.aiot-active .node-title,\n        .integration-node.aiot-active .node-subtitle {\n            color: #fff;\n        }\n.integration-node:hover:not(.aiot-active) {\n            border-color: #00AFF0;\n            transform: translateY(-2px);\n        }\n.node-icon {\n            width: 48px;\n            height: 48px;\n            background: linear-gradient(135deg, rgba(0, 175, 240, 0.1), rgba(0, 175, 240, 0.05));\n            border-radius: 12px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin: 0 auto 12px;\n        }\n.node-icon svg {\n            width: 24px;\n            height: 24px;\n            stroke: #00AFF0;\n            stroke-width: 1.5;\n            fill: none;\n        }\n.integration-node.aiot-active .node-icon {\n            background: rgba(255,255,255,0.2);\n        }\n.integration-node.aiot-active .node-icon svg {\n            stroke: #fff;\n        }\n.node-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #000864;\n            font-weight: 600;\n        }\n.node-subtitle {\n            font-size: 13px;\n            color: #5b6b80;\n            margin-top: 4px;\n        }\n.integration-message {\n            background: #fff;\n            border-radius: 20px;\n            padding: 40px 48px;\n            box-shadow: 0 8px 40px rgba(0, 0, 0, 0.06);\n            border: 1px solid #e8eef3;\n            text-align: center;\n            max-width: 800px;\n            margin: 0 auto;\n        }\n.integration-message p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #000864;\n            line-height: 1.8;\n            margin: 0;\n        }\n.integration-message strong {\n            color: #0369a1;\n        }\n.integration-links {\n            display: flex;\n            gap: 16px;\n            justify-content: center;\n            flex-wrap: wrap;\n            margin-top: 40px;\n        }\n.integration-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            padding: 14px 28px;\n            background: #fff;\n            border: 1px solid #e8eef3;\n            border-radius: 12px;\n            color: #0369a1;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            font-weight: 600;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n.integration-link:hover {\n            border-color: #00AFF0;\n            background: rgba(0, 175, 240, 0.05);\n            transform: translateY(-2px);\n        }\n.integration-link svg {\n            width: 16px;\n            height: 16px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n        }\n.integration-arrow {\n            color: #0369a1;\n            font-size: 24px;\n            font-weight: 700;\n        }\n@media (max-width: 640px) {\n            .integration-diagram { flex-direction: column; }\n            .integration-arrow { transform: rotate(90deg); }\n        }\n/* Rainbow gradient bar above message */\n.integration-gradient-bar{height:4px;border-radius:4px 4px 0 0;background:linear-gradient(90deg,#00AFF0,#003CC8,#644CE6,#FF6E82,#FFD700,#02D28C);margin:-1px 0 0}\n/* Divi overrides */\n.et_pb_section .integration-header h2{font-weight:700 !important;line-height:1.3 !important;font-size:36px !important}\n.et_pb_section .integration-header p{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .integration-message p{font-weight:400 !important;padding-bottom:0 !important;line-height:1.8 !important}\n.et_pb_section .node-t