ction":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: AIoT (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="aiot-hero">\n    <div class="dw-d-bg dw-d-bg--center dw-d-bg--particle dw-d-parallax" style="opacity: 0.12;"></div>\n            <div class="aiot-hero-inner">\n                <div class="aiot-hero-grid">\n                    <div class="aiot-hero-content">\n                        <div class="aiot-hero-badge">\n                            <span>Industrial Intelligence Platform</span>\n                        </div>\n                        <h1>เครื่องจักรของคุณ <span>รู้ทุกอย่าง</span><br>แต่คุณได้ยินมันหรือเปล่า?</h1>\n                        <p class="aiot-hero-subtitle">เครื่องจักรทุกเครื่องสร้างข้อมูลนับพันจุดทุกวัน DigiWin AIoT (ปัญญาประดิษฐ์แห่งสรรพสิ่ง) เก็บ วิเคราะห์ และแปลงข้อมูลเหล่านี้ให้เป็นความได้เปรียบทางการแข่งขัน</p>\n                        <div class="aiot-hero-stats">\n                            <div class="aiot-hero-stat">\n                                <div class="aiot-hero-stat-value">50+</div>\n                                <div class="aiot-hero-stat-label">โปรโตคอลที่รองรับ</div>\n                            </div>\n                            <div class="aiot-hero-stat">\n                                <div class="aiot-hero-stat-value">1M+</div>\n                                <div class="aiot-hero-stat-label">จุดข้อมูล/วัน</div>\n                            </div>\n                            <div class="aiot-hero-stat">\n                                <div class="aiot-hero-stat-value">< 1s</div>\n                                <div class="aiot-hero-stat-label">ตอบสนองแบบเรียลไทม์</div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="aiot-hero-visual">\n                        <div class="aiot-sensor-dashboard">\n                            <div class="aiot-dashboard-header">\n                                <span class="aiot-dashboard-title">Live Sensor Data</span>\n                                <span class="aiot-live-badge"><span class="aiot-live-dot"></span> Live</span>\n                            </div>\n                            <div class="aiot-sensor-grid">\n                                <div class="aiot-sensor-tile">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v20M2 12h20M4.93 4.93l14.14 14.14M4.93 19.07l14.14-14.14"/></svg></div>\n                                    <div class="aiot-sensor-value">78.4°C</div>\n                                    <div class="aiot-sensor-label">อุณหภูมิ</div>\n                                </div>\n                                <div class="aiot-sensor-tile warning">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2a10 10 0 1 0 0 20 10 10 0 1 0 0-20"/><path d="M12 6v6l4 2"/></svg></div>\n                                    <div class="aiot-sensor-value">2.4 mm/s</div>\n                                    <div class="aiot-sensor-label">การสั่นสะเทือน</div>\n                                </div>\n                                <div class="aiot-sensor-tile">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg></div>\n                                    <div class="aiot-sensor-value">47.2 kW</div>\n                                    <div class="aiot-sensor-label">กำลังไฟ</div>\n                                </div>\n                                <div class="aiot-sensor-tile">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg></div>\n                                    <div class="aiot-sensor-value">1,847</div>\n                                    <div class="aiot-sensor-label">RPM</div>\n                                </div>\n                            </div>\n                            <div class="aiot-machine-list">\n                                <div class="aiot-machine-row">\n                                    <span class="aiot-machine-name">CNC-M01</span>\n                                    <span class="aiot-machine-status running"><span class="aiot-status-dot"></span> กำลังทำงาน</span>\n                                </div>\n                                <div class="aiot-machine-row">\n                                    <span class="aiot-machine-name">CNC-M02</span>\n                                    <span class="aiot-machine-status idle"><span class="aiot-status-dot"></span> รอคิว</span>\n                                </div>\n                                <div class="aiot-machine-row">\n                                    <span class="aiot-machine-name">CNC-M03</span>\n                                    <span class="aiot-machine-status running"><span class="aiot-status-dot"></span> กำลังทำงาน</span>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: AIoT คืออะไร? (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: AIoT คืออะไร? (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: AIoT คืออะไร? (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 40px 0 0; text-align: center;">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 22px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">AIoT (Artificial Intelligence + Internet of Things) คืออะไร?</h2>\n        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333; margin: 0 0 24px 0;">\n          AIoT คือเทคโนโลยีที่เชื่อมต่อเครื่องจักรและเซ็นเซอร์ในโรงงาน เพื่อเก็บข้อมูลการผลิตแบบเรียลไทม์ จากนั้นใช้ AI วิเคราะห์เพื่อคาดการณ์ความต้องการซ่อมบำรุงและเพิ่มประสิทธิภาพ เปลี่ยนสัญญาณเครื่องจักรดิบให้เป็นข้อมูลที่ใช้ตัดสินใจได้ — ให้คุณป้องกันปัญหาก่อนเกิด แทนที่จะแก้ไขหลังเกิด\n        </p>\n        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333;">\n          <strong>DigiWin AIoT</strong> เป็นแพลตฟอร์ม Industrial IoT ที่เชื่อมต่อเครื่องจักรทุกยี่ห้อ ทุกโปรโตคอล เข้าสู่ชั้นข้อมูลเดียวกัน รองรับกว่า 50+ โปรโตคอลอุตสาหกรรม — รวมถึง OPC-UA, Modbus, MQTT, Fanuc, Siemens และ Mitsubishi — เก็บข้อมูลกว่า 1 ล้านจุดต่อวัน จากเครื่อง CNC, PLC, เซ็นเซอร์ และมิเตอร์ไฟฟ้า แพลตฟอร์มช่วยให้ติดตาม OEE แบบเรียลไทม์, ซ่อมบำรุงเชิงคาดการณ์, บริหารพลังงาน และติดตามสิ่งแวดล้อม โดยโรงงานไทยได้ OEE เพิ่มขึ้นเฉลี่ย 15% และลด Unplanned Downtime ลง 40%\n        </p>\n      </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem: โรงงานส่วนใหญ่บินตาบอด (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem: โรงงานส่วนใหญ่บินตาบอด (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem: โรงงานส่วนใหญ่บินตาบอด (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="problem-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <rect x="100" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="150" cy="340" r="15" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <path d="M200 340 L300 340" stroke="#000864" stroke-width="1.5" opacity="0.1" stroke-dasharray="6 4"/>\n                    <g opacity="0.4"><line x1="290" y1="330" x2="310" y2="350" stroke="#00AFF0" stroke-width="2"/><line x1="310" y1="330" x2="290" y2="350" stroke="#00AFF0" stroke-width="2"/></g>\n                    <rect x="400" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="450" cy="340" r="15" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <path d="M500 340 L600 340" stroke="#000864" stroke-width="1.5" opacity="0.1" stroke-dasharray="6 4"/>\n                    <g opacity="0.35"><line x1="590" y1="330" x2="610" y2="350" stroke="#00AFF0" stroke-width="2"/><line x1="610" y1="330" x2="590" y2="350" stroke="#00AFF0" stroke-width="2"/></g>\n                    <rect x="700" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="750" cy="340" r="15" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <path d="M800 340 L900 340" stroke="#000864" stroke-width="1.5" opacity="0.1" stroke-dasharray="6 4"/>\n                    <g opacity="0.3"><line x1="890" y1="330" x2="910" y2="350" stroke="#00AFF0" stroke-width="2"/><line x1="910" y1="330" x2="890" y2="350" stroke="#00AFF0" stroke-width="2"/></g>\n                    <path d="M150 250 Q150 230 160 230" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.15"/>\n                    <path d="M150 245 Q150 220 165 220" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <path d="M150 240 Q150 210 170 210" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.1"/>\n                    <path d="M450 250 Q450 230 460 230" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.15"/>\n                    <path d="M450 245 Q450 220 465 220" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <path d="M750 250 Q750 230 760 230" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.15"/>\n                    <path d="M750 245 Q750 220 765 220" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <rect x="1050" y="200" width="200" height="120" rx="8" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <line x1="1070" y1="250" x2="1130" y2="250" stroke="#000864" stroke-width="0.5" opacity="0.1"/>\n                    <line x1="1070" y1="265" x2="1200" y2="265" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="1070" y1="280" x2="1180" y2="280" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <text x="1090" y="230" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="700" fill="#000864" opacity="0.08">NO DATA</text>\n                    <circle cx="300" cy="600" r="3" fill="#000864" opacity="0.1"/>\n                    <circle cx="600" cy="550" r="4" fill="#000864" opacity="0.08"/>\n                    <circle cx="900" cy="600" r="3" fill="#00AFF0" opacity="0.1"/>\n                    <circle cx="1200" cy="500" r="3" fill="#000864" opacity="0.08"/>\n                    <text x="500" y="700" font-family="\'Noto Sans\',sans-serif" font-size="28" font-weight="800" fill="#000864" opacity="0.05">?</text>\n                </svg>\n            </div>\n            <div class="problem-header" style="position: relative; z-index: 2;">\n                <h2>โรงงานส่วนใหญ่บริหารแบบตาบอด</h2>\n                <p>เครื่องจักรของคุณพูดอยู่ แต่ถ้าไม่มีหูที่ใช่ คุณกำลังพลาดข้อมูลสำคัญ</p>\n            </div>\n            <div class="problem-grid" style="position: relative; z-index: 2;">\n                <div class="problem-card">\n                    <div class="problem-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></svg></div>\n                    <h3>เครื่องจักรเงียบ</h3>\n                    <p>เครื่องจักรทำงานโดยไม่รายงาน ปัญหาถูกพบหลังจากเครื่องเสียแล้วเท่านั้น</p>\n                </div>\n                <div class="problem-card">\n                    <div class="problem-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg></div>\n                    <h3>ซ่อมแบบตั้งรับ</h3>\n                    <p>เสียแล้วค่อยซ่อม Downtime ที่ไม่ได้วางแผนมีต้นทุนมากกว่าการซ่อมบำรุงตามกำหนด 10 เท่า</p>\n                </div>\n                <div class="problem-card">\n                    <div class="problem-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><rect x="8" y="2" width="8" height="4" rx="1" ry="1"/><line x1="9" y1="12" x2="15" y2="12"/><line x1="9" y1="16" x2="15" y2="16"/></svg></div>\n                    <h3>OEE แบบแมนนวล</h3>\n                    <p>พนักงานจดบันทึกการผลิตบนกระดาษ ข้อมูลมาช้า ไม่แม่นยำ หรือไม่ได้เก็บเลย</p>\n                </div>\n                <div class="problem-card">\n                    <div class="problem-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg></div>\n                    <h3>พลังงานสูญเปล่าที่มองไม่เห็น</h3>\n                    <p>ไม่รู้ว่าเครื่องไหนกินไฟเท่าไหร่ ค่าไฟพุ่งโดยไม่มีคำอธิบาย</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dataflow: วิธีการทำงาน (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dataflow: วิธีการทำงาน (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dataflow: วิธีการทำงาน (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dataflow-section">\n    <div class="dataflow-header" style="position: relative; z-index: 2;">\n                <h2>DigiWin AIoT ทำงานอย่างไร</h2>\n                <p>จากสัญญาณเครื่องจักรสู่ข้อมูลเชิงลึกที่นำไปใช้ได้ทันที — แบบเรียลไทม์</p>\n            </div>\n            <div class="dataflow-visual" style="position: relative; z-index: 2;">\n                <div class="dataflow-stages">\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">1</div>\n                        <h3>เชื่อมต่อ</h3>\n                        <p>Edge device เก็บข้อมูลจากเครื่องจักรทุกยี่ห้อ ทุกรุ่น ทุกอายุ</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">PLCs</span>\n                            <span class="dataflow-item">CNCs</span>\n                            <span class="dataflow-item">เซ็นเซอร์</span>\n                            <span class="dataflow-item">มิเตอร์</span>\n                        </div>\n                    </div>\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">2</div>\n                        <h3>แปลภาษา</h3>\n                        <p>รองรับโปรโตคอลสากล เปลี่ยนสัญญาณให้เป็นข้อมูลมาตรฐาน</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">OPC-UA</span>\n                            <span class="dataflow-item">Modbus</span>\n                            <span class="dataflow-item">MQTT</span>\n                            <span class="dataflow-item">MT Connect</span>\n                        </div>\n                    </div>\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">3</div>\n                        <h3>วิเคราะห์</h3>\n                        <p>โมเดล AI ตรวจจับรูปแบบ คาดการณ์ความเสียหาย ปรับประสิทธิภาพ</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">OEE</span>\n                            <span class="dataflow-item">ความผิดปกติ</span>\n                            <span class="dataflow-item">แนวโน้ม</span>\n                            <span class="dataflow-item">การแจ้งเตือน</span>\n                        </div>\n                    </div>\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">4</div>\n                        <h3>ลงมือทำ</h3>\n                        <p>แดชบอร์ด การแจ้งเตือน และการเชื่อมต่อระบบ ขับเคลื่อนการตัดสินใจทันที</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">ERP</span>\n                            <span class="dataflow-item">MES</span>\n                            <span class="dataflow-item">มือถือ</span>\n                            <span class="dataflow-item">Andon</span>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: ความสามารถ Smart Factory (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: ความสามารถ Smart Factory (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: ความสามารถ Smart Factory (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="capabilities-section">\n    <div class="capabilities-header" style="position: relative; z-index: 2;">\n                <h2>ความสามารถ Smart Factory</h2>\n                <p>เห็นภาพครบตั้งแต่สัญญาณเครื่องจักรจนถึงข้อมูลเชิงธุรกิจ</p>\n            </div>\n            <div class="capabilities-grid" style="position: relative; z-index: 2;">\n                <div class="capability-card">\n                    <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v6m0 8v6M6 12H2m20 0h-4"/><circle cx="12" cy="12" r="4"/><path d="M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/></svg></div>\n                    <h3>เชื่อมต่อเครื่องจักรสากล</h3>\n                    <p>เชื่อมต่อเครื่องจักรทุกยี่ห้อ ทุกโปรโตคอล ทุกอายุ Edge device ของเราพูดได้ทุกภาษาที่โรงงานคุณใช้</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>เชื่อมต่อ PLC</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>เครื่อง CNC/SMT</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>เครือข่ายเซ็นเซอร์</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>อุปกรณ์เก่า</span>\n                        </div>\n                    </div>\n                </div>\n                <div class="capability-card">\n                    <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M18 20V10M12 20V4M6 20v-6"/></svg></div>\n                    <h3>OEE แบบเรียลไทม์</h3>\n                    <p>คำนวณ OEE อัตโนมัติจากสัญญาณเครื่องจักร ดู Availability, Performance และ Quality โดยไม่ต้องป้อนข้อมูลเอง</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>ติดตาม Downtime อัตโนมัติ</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>วิเคราะห์ Cycle Time</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>ความสัมพันธ์คุณภาพ</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>เปรียบเทียบกะ</span>\n                        </div>\n                    </div>\n                </div>\n                <div class="capability-card">\n                    <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4M12 8h.01"/><path d="M8 14s1.5 2 4 2 4-2 4-2"/></svg></div>\n                    <h3>ซ่อมบำรุงเชิงคาดการณ์</h3>\n                    <p>โมเดล AI เรียนรู้พฤติกรรมเครื่องจักรของคุณ คาดการณ์ความเสียหายก่อนเกิด ซ่อมก่อนพัง</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>วิเคราะห์การสั่นสะเทือน</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>แนวโน้มอุณหภูมิ</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>ตรวจจับความผิดปกติ</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>ใบสั่งซ่อมอัตโนมัติ</span>\n                        </div>\n                    </div>\n                </div>\n                <div class="capability-card">\n                    <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg></div>\n                    <h3>บริหารพลังงาน</h3>\n                    <p>ติดตามการใช้พลังงานตามเครื่อง สายการผลิต และผลิตภัณฑ์ ค้นหาจุดสูญเปล่า ลดต้นทุน บรรลุเป้าหมายความยั่งยืน</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>ติดตามแบบเรียลไทม์</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>ต้นทุนต่อหน่วย</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>แจ้งเตือน Peak Demand</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Carbon Footprint</span>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metrics: ผลลัพธ์ที่วัดได้ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metrics: ผลลัพธ์ที่วัดได้ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metrics: ผลลัพธ์ที่วัดได้ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="metrics-section" data-particles="bold">\n    <div class="metrics-header" style="position:relative;z-index:2;">\n                <h2>ผลลัพธ์ที่วัดได้จริง</h2>\n                <p>สิ่งที่ลูกค้าของเราทำได้หลังติดตั้ง AIoT</p>\n            </div>\n            <div class="metrics-grid" style="position:relative;z-index:2;">\n                <div class="metric-card">\n                    <div class="metric-value">+15%</div>\n                    <div class="metric-label">OEE เพิ่มขึ้น</div>\n                </div>\n                <div class="metric-card">\n                    <div class="metric-value">-40%</div>\n                    <div class="metric-label">Unplanned Downtime ลดลง</div>\n                </div>\n                <div class="metric-card">\n                    <div class="metric-value">-12%</div>\n                    <div class="metric-label">ค่าพลังงานลดลง</div>\n                </div>\n                <div class="metric-card">\n                    <div class="metric-value">100%</div>\n                    <div class="metric-label">ความแม่นยำของข้อมูล</div>\n                </div>\n            </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protocol: โปรโตคอลที่รองรับ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protocol: โปรโตคอลที่รองรับ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protocol: โปรโตคอลที่รองรับ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="protocol-section">\n    <div class="dw-d-bg dw-d-bg--corner-tl dw-d-bg--subtle" style="opacity: 0.10;"></div>\n            <div class="protocol-inner" style="position: relative; z-index: 2;">\n                <h3>โปรโตคอลและอุปกรณ์ที่รองรับ</h3>\n                <div class="protocol-grid">\n                    <div class="protocol-tag">OPC-UA</div>\n                    <div class="protocol-tag">Modbus TCP/RTU</div>\n                    <div class="protocol-tag">MQTT</div>\n                    <div class="protocol-tag">MT Connect</div>\n                    <div class="protocol-tag">PROFINET</div>\n                    <div class="protocol-tag">EtherNet/IP</div>\n                    <div class="protocol-tag">Siemens S7</div>\n                    <div class="protocol-tag">Mitsubishi MELSEC</div>\n                    <div class="protocol-tag">FANUC FOCAS</div>\n                    <div class="protocol-tag">Allen-Bradley</div>\n                    <div class="protocol-tag">Omron FINS</div>\n                    <div class="protocol-tag">BACnet</div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration: ชั้นข้อมูลอัจฉริยะ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration: ชั้นข้อมูลอัจฉริยะ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration: ชั้นข้อมูลอัจฉริยะ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="integration-section">\n    <div class="integration-header">\n                <h2>ชั้นข้อมูลอัจฉริยะ</h2>\n                <p>AIoT เชื่อมต่อเครื่องจักรของคุณกับระบบธุรกิจ</p>\n            </div>\n            <div class="integration-diagram">\n                <a href="erp.html" class="integration-node">\n                    <div class="node-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg></div>\n                    <div class="node-title">ERP</div>\n                    <div class="node-subtitle">T100 / iGP</div>\n                </a>\n                <span class="integration-arrow">↔</span>\n                <a href="mes.html" class="integration-node">\n                    <div class="node-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><line x1="6" y1="12" x2="6" y2="12"/><line x1="10" y1="12" x2="10" y2="12"/><line x1="14" y1="12" x2="14" y2="12"/><line x1="18" y1="12" x2="18" y2="12"/></svg></div>\n                    <div class="node-title">MES</div>\n                    <div class="node-subtitle">MES / SFT</div>\n                </a>\n                <span class="integration-arrow">↔</span>\n                <div class="integration-node aiot-active">\n                    <div class="node-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/><circle cx="12" cy="12" r="3"/></svg></div>\n                    <div class="node-title">AIoT</div>\n                    <div class="node-subtitle">ชั้นเครื่องจักร</div>\n                </div>\n                <span class="integration-arrow">↔</span>\n                <a href="wms.html" class="integration-node">\n                    <div class="node-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.29 7 12 12 20.71 7"/><line x1="12" y1="22" x2="12" y2="12"/></svg></div>\n                    <div class="node-title">WMS</div>\n                    <div class="node-subtitle">sFLS</div>\n                </a>\n            </div>\n\n            <div class="integration-message">\n                <div class="integration-gradient-bar" aria-hidden="true"></div>\n                <p>ข้อมูลเครื่องจักรไหลจากเซ็นเซอร์สู่แดชบอร์ดแบบเรียลไทม์ AIoT ส่ง OEE ไป MES, สั่งซ่อมบำรุงใน ERP และตรวจสอบสินค้าคงคลังใน WMS <strong>หนึ่งโรงงานที่เชื่อมต่อ ไม่มีจุดบอด</strong></p>\n            </div>\n\n            <div class="integration-links">\n                <a href="erp.html" class="integration-link">สำรวจ ERP <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                <a href="mes.html" class="integration-link">สำรวจ MES <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                <a href="wms.html" class="integration-link">สำรวจ WMS <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: AIoT (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: AIoT (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: AIoT (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="aiot-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">Frequently Asked Questions</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Industrial AIoT คืออะไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Industrial AIoT (Artificial Intelligence of Things — ปัญญาประดิษฐ์แห่งสรรพสิ่ง) ผสมผสานการเชื่อมต่อเซ็นเซอร์ IoT เข้ากับการวิเคราะห์ด้วย AI สำหรับการผลิต เชื่อมต่อเครื่องจักร PLC และเซ็นเซอร์ในโรงงานเข้าสู่แพลตฟอร์มข้อมูลเดียว ที่ติดตามสุขภาพอุปกรณ์ คำนวณ OEE อัตโนมัติ คาดการณ์ความเสียหายก่อนเกิด และปรับการใช้พลังงานให้เหมาะสม — เปลี่ยนข้อมูลดิบจากเครื่องจักรให้เป็นข้อมูลที่ใช้ตัดสินใจได้</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin AIoT รองรับเครื่องจักรและโปรโตคอลอะไรบ้าง?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin AIoT รองรับกว่า 50+ โปรโตคอลอุตสาหกรรม รวมถึง OPC-UA, Modbus TCP/RTU, MQTT, MT Connect, PROFINET, EtherNet/IP, Siemens S7, Mitsubishi MELSEC, FANUC FOCAS, Allen-Bradley, Omron FINS และ BACnet เชื่อมต่อได้ทั้งเครื่อง CNC, เครื่องฉีดพลาสติก, PLC, หุ่นยนต์, มิเตอร์ไฟฟ้า และเซ็นเซอร์สิ่งแวดล้อม จากทุกยี่ห้อและทุกอายุ</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">ต้องเปลี่ยนเครื่องจักรเดิมหรือไม่ถึงจะใช้ AIoT ได้?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">ไม่ต้อง DigiWin AIoT ติดตั้งเพิ่มบนอุปกรณ์เดิมได้โดยไม่ต้องเปลี่ยนเครื่อง ไม่ว่าจะอายุหรือยี่ห้อใด Edge device เชื่อมต่อกับ PLC, CNC หรือเพิ่มเซ็นเซอร์ภายนอก (การสั่นสะเทือน, อุณหภูมิ, กำลังไฟ) กับเครื่องที่ไม่มี Digital Output แม้แต่เครื่องอายุ 20 ปีก็เชื่อมต่อได้โดยไม่ต้องดัดแปลงเครื่องจักร</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">AIoT เชื่อมต่อกับ ERP และ MES อย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin AIoT สร้างบนแพลตฟอร์มเดียวกับ DigiWin ERP และ MES ใช้ฐานข้อมูลร่วมกัน ข้อมูลเครื่องจักรไหลอัตโนมัติจากเซ็นเซอร์ผ่าน AIoT เข้า MES สำหรับคำนวณ OEE และเข้า ERP สำหรับใบสั่งซ่อมและต้นทุนการผลิต ไม่ต้องใช้ Middleware ไม่ต้องป้อนข้อมูลเอง ไม่ต้องมีโปรเจกต์ Integration แยก</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">ROI ที่คาดหวังจาก Factory AIoT เป็นอย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">ลูกค้า DigiWin AIoT โดยทั่วไปได้ OEE เพิ่มขึ้น 15%, Unplanned Downtime ลดลง 40% และค่าพลังงานลดลง 12% โรงงานส่วนใหญ่คืนทุนภายใน 6-12 เดือน ผลลัพธ์ที่เห็นทันทีมาจากการลดการเก็บข้อมูลด้วยมือ และทำให้สถานะเครื่องจักรมองเห็นได้แบบเรียลไทม์</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: เริ่มฟังเครื่องจักรของคุณ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: เริ่มฟังเครื่องจักรของคุณ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: เริ่มฟังเครื่องจักรของคุณ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="aiot-cta-section">\n    <div class="aiot-cta-super-d" aria-hidden="true"></div>\n    <div class="aiot-cta-wave-flow" aria-hidden="true"></div>\n    <div class="aiot-cta-container">\n      <h2 class="aiot-cta-title">เริ่มฟังเครื่องจักรของคุณ</h2>\n      <p class="aiot-cta-subtitle">ดูว่าสายการผลิตของคุณเป็นอย่างไรจริงๆ</p>\n      <div class="aiot-cta-btn-row">\n        <a href="/th/demo/" class="aiot-cta-btn aiot-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/products.html" class="aiot-cta-btn aiot-cta-btn--ghost">ดูโซลูชันทั้งหมด</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.aiot-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.aiot-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.aiot-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.aiot-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="aiot-related-section">\n    <h2 class="aiot-related-heading">Explore Related Solutions</h2>\n    <div class="aiot-related-grid">\n      <a href="/products/erp/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">ERP</h3>\n        <p class="aiot-related-card-desc">ระบบ ERP สำหรับโรงงานผลิตครบวงจร — ตั้งแต่ BOM ถึงบัญชีการเงินถึง BOI</p>\n      </a>\n      <a href="/products/mes/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">MES</h3>\n        <p class="aiot-related-card-desc">ระบบบริหารการผลิตแบบเรียลไทม์ — ติดตาม OEE, SPC และใบสั่งผลิตแบบไร้กระดาษ</p>\n      </a>\n      <a href="/products/wms/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">WMS</h3>\n        <p class="aiot-related-card-desc">ระบบบริหารคลังสินค้าอัจฉริยะ Barcode/RFID — ตั้งแต่รับเข้าถึงจัดส่ง พร้อม Traceability เต็มรูปแบบ</p>\n      </a>\n      <a href="/industries/automotive/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">Automotive</h3>\n        <p class="aiot-related-card-desc">ระบบ ERP และ MES ที่ออกแบบเฉพาะสำหรับผู้ผลิตชิ้นส่วนยานยนต์และ OEM Supplier</p>\n      </a>\n      <a href="/industries/electronics/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">Electronics</h3>\n        <p class="aiot-related-card-desc">ซอฟต์แวร์การผลิตสำหรับงานประกอบอิเล็กทรอนิกส์ สาย SMT และ Component Traceability</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">Metal &amp; Plastics</h3>\n        <p class="aiot-related-card-desc">โซลูชันครบวงจรสำหรับ Die Casting, ฉีดพลาสติก และโรงงานขึ้นรูปโลหะ</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100780;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100780 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100780, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.aiot-hero {\n            background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);\n            padding: 140px 0 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.aiot-hero::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%233798E4\' fill-opacity=\'0.08\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            opacity: 0.5;\n        }\n.aiot-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            position: relative;\n            z-index: 1;\n        }\n.aiot-hero-grid {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 60px;\n            align-items: center;\n        }\n.aiot-hero-content {\n            text-align: left;\n        }\n.aiot-hero-visual {\n            display: flex;\n            justify-content: center;\n        }\n.aiot-sensor-dashboard {\n            background: rgba(255,255,255,0.08);\n            border: 1px solid rgba(255,255,255,0.15);\n            border-radius: 16px;\n            padding: 24px;\n            width: 100%;\n            max-width: 480px;\n            backdrop-filter: blur(8px);\n        }\n.aiot-dashboard-header {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            margin-bottom: 20px;\n            padding-bottom: 12px;\n            border-bottom: 1px solid rgba(255,255,255,0.1);\n        }\n.aiot-dashboard-title {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: #7EC8F2;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        }\n.aiot-live-badge {\n            display: flex;\n            align-items: center;\n            gap: 6px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: #22c55e;\n            text-transform: uppercase;\n        }\n.aiot-live-dot {\n            width: 6px;\n            height: 6px;\n            background: #22c55e;\n            border-radius: 50%;\n            animation: pulse-dot 1.5s infinite;\n        }\n.aiot-sensor-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 12px;\n            margin-bottom: 20px;\n        }\n.aiot-sensor-tile {\n            background: rgba(0, 175, 240, 0.15);\n            border: 1px solid rgba(0, 175, 240, 0.25);\n            border-radius: 10px;\n            padding: 16px;\n            text-align: center;\n        }\n.aiot-sensor-tile.warning {\n            background: rgba(251, 191, 36, 0.15);\n            border-color: rgba(251, 191, 36, 0.3);\n        }\n.aiot-sensor-tile.alert {\n            background: rgba(239, 68, 68, 0.15);\n            border-color: rgba(239, 68, 68, 0.3);\n        }\n.aiot-sensor-icon {\n            width: 28px;\n            height: 28px;\n            margin: 0 auto 8px;\n        }\n.aiot-sensor-icon svg {\n            width: 100%;\n            height: 100%;\n            stroke: #7EC8F2;\n            stroke-width: 1.5;\n            fill: none;\n        }\n.aiot-sensor-tile.warning .aiot-sensor-icon svg {\n            stroke: #fbbf24;\n        }\n.aiot-sensor-tile.alert .aiot-sensor-icon svg {\n            stroke: #ef4444;\n        }\n.aiot-sensor-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 22px;\n            font-weight: 600;\n            color: #fff;\n            margin-bottom: 2px;\n        }\n.aiot-sensor-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 9px;\n            color: rgba(255,255,255,0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n        }\n.aiot-machine-list {\n            display: flex;\n            flex-direction: column;\n            gap: 8px;\n        }\n.aiot-machine-row {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            background: rgba(255,255,255,0.05);\n            border-radius: 8px;\n            padding: 10px 14px;\n        }\n.aiot-machine-name {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: rgba(255,255,255,0.8);\n        }\n.aiot-machine-status {\n            display: flex;\n            align-items: center;\n            gap: 6px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n        }\n.aiot-m